import { BtcWallet, BtcHotWallet } from './wallet';
import { default as HotWalletTool } from './wallet-tools/HotWalletTool';
import { default as SendWalletTool } from './wallet-tools/SendWalletTool';
import { default as TransactionTool } from './wallet-tools/TransactionTool';
import { default as TransferWalletTool } from './wallet-tools/TransferWalletTool';

export default class WalletToolFactory {
    static createTransactionTool<T extends BtcWallet | BtcHotWallet>(wallet: T): TransactionTool<T>;
    static createSendWalletTool<T extends BtcWallet | BtcHotWallet>(wallet: T): SendWalletTool<T>;
    static createTransferWalletTool<T extends BtcWallet | BtcHotWallet>(wallet: T): TransferWalletTool<T>;
    static createHotWalletTool(wallet: BtcHotWallet): HotWalletTool;
}
